// Configure OkHttpClient with Interceptor for authentication
class AuthInterceptor(private val tokenProvider: () -> String) : Interceptor {
    override fun intercept(chain: Interceptor.Chain): Response {
        val request: Request = chain.request().newBuilder()
            .addHeader("Authorization", "Bearer ${tokenProvider()}")
            .build()
        return chain.proceed(request)
    }
}

// Retrofit Service interface
interface ApiService {
    @GET("users/{userId}")
    @Headers("Content-Type: application/json")
    suspend fun getUserProfile(@Path("userId") userId: String): UserProfile
}

// Retrofit client
object NetworkModule {
    private fun createRetrofit(baseUrl: String, authInterceptor: AuthInterceptor): Retrofit {
        val okHttpClient = OkHttpClient.Builder()
            .addInterceptor(authInterceptor)
            .build()

        return Retrofit.Builder()
            .baseUrl(baseUrl)
            .client(okHttpClient)
            .addConverterFactory(GsonConverterFactory.create())
            .build()
    }
    
    fun createApiService(environment: String, tokenProvider: () -> String): ApiService {
        val authInterceptor = AuthInterceptor(tokenProvider)
        val retrofit = createRetrofit(environment, authInterceptor)
        return retrofit.create(ApiService::class.java)
    }
}

